class Admin_Model_ProductStock extends Admin_Model_Base_ProductStock
{

    public static function deleteProductStock(int $productID) {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_ProductStock ps');
        $query->where('ps.Product_ID = ?', $productID);
        $query->execute();
    }

    public static function getProductStockByProductStockID(int $productStockID) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductStock ps');
        $query->where('ps.ID = ?', $productStockID);
        return $query->fetchOne();
    }

    /**
     * @throws Doctrine_Query_Exception
     */
    public static function getProductStocksByProductID(int $productID): Doctrine_Collection {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductStock ps');
        $query->where('ps.Product_ID = ?', $productID);
        return $query->execute();
    }

    /**
     * @throws Doctrine_Query_Exception
     */
    public static function getProductStocksByProductCode(string $productCode): null | Doctrine_Collection {
        $product = Admin_Model_Product::getProductByCode($productCode);
        if(!$product) {
            return null;
        }
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductStock ps');
        $query->where('ps.Product_ID = ?', $product->ID);
        return $query->execute();
    }

    public static function getProductStockByProductIDAndWarehouseCode(int $productID = null, string $productCode = null, string $warehouseCode = null) {
        if(!$productID && $productCode) {
            $product = Admin_Model_Product::getProductByCode($productCode);
            if($product) {
                $productID = $product->ID;
            }
        }
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductStock ps');
        $query->innerJoin('ps.stock s');
        $query->where('ps.Product_ID = ?', $productID);
        $query->andWhere('s.Code = ?', $warehouseCode);
        return $query->fetchOne();
    }

    public static function getProductsQuantityInfoByProductIDs(array $productIDs): array {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_ProductStock ps');
        $query->addSelect('ps.Product_ID, SUM(ps.Quantity) as TotalQuantity, p.Code as ProductCode, pl.Name as ProductName, pl.slug as ProductSlug');
        $query->leftJoin('ps.product p');
        $query->leftJoin('p.productLangs pl WITH pl.Language_ID = ?', Eshop::getInstance()->getEshop()->Language_ID);
        $query->whereIn('ps.Product_ID', $productIDs);
        $query->groupBy('ps.Product_ID');
        $query->having('SUM(ps.Quantity) > 0');
        return $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
    }


}